import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as r,e as d}from"./app-e35f2bf1.js";const c={},s=d(`<h2 id="背景" tabindex="-1"><a class="header-anchor" href="#背景" aria-hidden="true">#</a> 背景</h2><p>背景是在重构完 Signal 之后，一开始用我们自己的 libc 测试 signal 功能没有问题，但是在用 relibc 测试的时候出问题了，出错的原因就是一个 Userland 的 General Protection(GP)，这个东西是一个硬件异常，通常是由于汇编指令出错或者内存访问出错导致，比如把一个未对齐的内存地址作为某个指令的操作数，而这个指令要求这个内存地址是 8/16 对齐的。</p><h2 id="初步分析" tabindex="-1"><a class="header-anchor" href="#初步分析" aria-hidden="true">#</a> 初步分析</h2><p>在查看 GP 的 RIP ，反汇编了用户空间的测试程序之后，看到了对应的汇编代码是</p><div class="language-x86asm line-numbers-mode" data-ext="x86asm"><pre class="language-x86asm"><code>movapd %XMM0 0xe0(rsp)
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>也就是说，这个地方是把寄存器的值写到栈上，查手册后得知， <code>movapd</code> 操作要求操作数是 <code>16 对齐</code>的，不对齐的话就会触发 GP ，现在问题就比较清晰了，大概就是 rsp 没有 16 对齐，接下来就是排查 rsp 的情况了。</p><blockquote><p>这里还发现了之前信号处理流程中没有正确保存浮点寄存器和清空浮点寄存器的bug，不过修复了这个bug之后还是没有解决 GP 的问题，所以这里先不提了。</p></blockquote><h2 id="进一步分析" tabindex="-1"><a class="header-anchor" href="#进一步分析" aria-hidden="true">#</a> 进一步分析</h2><p>在信号处理流程中，在设置用户栈帧的时候是需要手动修改传入的中断栈帧的一系列寄存器，包括 rip\\rsp，并且保存这个上下文，然后在信号处理函数调用结束之后恢复的，所以这里很自然的就会开始排查，是不是 <code>setup_frame</code>，也就是设置栈帧的时候出了问题，比如没有 16对齐 rsp。但是经过一番排查之后，发现在 <code>setup_frame</code> 函数返回的时候，rsp 已经 16 对齐了，所以这里排除 <code>setup_frame</code> 函数的问题。然后就会想，是不是哪里写坏栈了，或者在 <code>sertup_frame</code> 函数返回的时候，用户空间函数执行之前，还有什么地方对 rsp 进行了修改。但是很快就排除了这个问题。</p><h2 id="陷入僵局" tabindex="-1"><a class="header-anchor" href="#陷入僵局" aria-hidden="true">#</a> 陷入僵局</h2><p>到这就很奇怪了，返回的时候还是 16 对齐的，到了用户空间执行的时候就变成非16对齐的了。又想不到哪里会修改 rsp 的值，而且因为现在 DragonOS 还没有支持用户空间的 GDB 调试 (因为没有ptrace)，所以我们就把这个用户程序 dump 出来，看里面的汇编对 rsp 是不是有操作的。</p><blockquote><p>这里我们又犯了一点小错误，就是在看汇编的时候，我们发现了在调用入口到报错位置有奇数个 push 指令，意思就是尽管传进来的是 16对齐但是到报错位置，rsp实际上就变成 8 对齐了，不过后来发现是在上一级调用的时候有个 callq，这个指令会压栈，所以实际上还是偶数个push指令，也就是与调用入口的对齐一致</p></blockquote><p>然后发现也没什么异常，于是乎到这里就陷入僵局了。</p><h2 id="跑着先" tabindex="-1"><a class="header-anchor" href="#跑着先" aria-hidden="true">#</a> 跑着先</h2><p>因为出错位置是在浮点周围，所以我们就选择在rust编译的时候开启软浮点，关闭硬件浮点支持，试试能不能跑起来。果不其然是能跑起来的，但是在 <code>sigreturn</code> 的时候报错了。于是这里又开始排查这个问题</p><h2 id="好像" tabindex="-1"><a class="header-anchor" href="#好像" aria-hidden="true">#</a> 好像</h2><p>经过排查之后，发现是没有正确调用用户空间的 <code>sigreturn</code> 函数，也就没有调用内核的<code>sigreturn</code> 函数，然后打日志发现，用户空间传入内核的 <code>sig_restorer</code> (值恒为用户空间的 <code>sigreturn</code> 函数指针)有问题，但是在 relibc 中打日志发现是没问题的，到这一步就发现事情好像有点露出鸡脚了。</p><h2 id="真相大白" tabindex="-1"><a class="header-anchor" href="#真相大白" aria-hidden="true">#</a> 真相大白</h2><p>然后 @longjin 提醒我检查内核的结构体是否与用户空间传入的结构体一致，我一看，真不一样，把这个一改，果然就跑起来了。开了硬件浮点之后之前的问题也不再出现了。但是为什么之前的 libc 能跑，这就是一个未解之谜了。经此一事，我们就要知道对于用户空间传入的数据要保持 100% 的敬畏之心，因为出现的错误很有可能千奇百怪。</p>`,19),o=[s];function i(n,t){return a(),r("div",null,o)}const l=e(c,[["render",i],["__file","记一次 GP Debug 的心路历程.html.vue"]]);export{l as default};
